            byte[] abiHandle = { 111, 122, 12, 210 };
            var token_in_idxAbi = new AVM.ClientGenerator.ABI.ARC4.Types.UInt64(); token_in_idxAbi.From(token_in_idx);
            var token_out_idxAbi = new AVM.ClientGenerator.ABI.ARC4.Types.UInt64(); token_out_idxAbi.From(token_out_idx);

            var result = await base.SimApp(new List<object> { abiHandle, token_in_idxAbi, token_out_idxAbi }, _tx_fee: _tx_fee, _tx_callType: _tx_callType, _tx_roundValidity: _tx_roundValidity, _tx_note: _tx_note, _tx_sender: _tx_sender, _tx_transactions: _tx_transactions, _tx_apps: _tx_apps, _tx_assets: _tx_assets, _tx_accounts: _tx_accounts, _tx_boxes: _tx_boxes);
            var lastLogBytes = result.Last();
            if (lastLogBytes.Length < 4 || lastLogBytes[0] != 21 || lastLogBytes[1] != 31 || lastLogBytes[2] != 124 || lastLogBytes[3] != 117) throw new Exception("Invalid ABI handle");
            var lastLogReturnData = lastLogBytes.Skip(4).ToArray();
            var returnValueObj = new AVM.ClientGenerator.ABI.ARC4.Types.UInt64();
            returnValueObj.Decode(lastLogReturnData);
